/**
 *
 * Patobulinimai:
 * - Bug 2: hood entity imama iš global.komfovent_entities
 * - Bug 3: predictive gerbia input_boolean.komfovent_predictive
 * - Patobulinimas 1: local rate fallback iš paskutinių CO₂ taškų
 * - Patobulinimas 2: 30 min bucket support
 */

function clamp(min, max, v) {
  return Math.max(min, Math.min(max, v));
}

const matrix = global.get('prediction_matrix') || null;
const ents = global.get('komfovent_entities') || {};
const TZ = 'Europe/Vilnius';

const schema_ver = Number(global.get('schema_ver') || 0);
const flow_ver = String(global.get('system_version') || 0);

const ha = global.get('homeassistant') || {};
const states =
  ha?.homeAssistant?.states ||
  ha?.homeassistant?.states ||
  ha?.states ||
  {};

function getState(id) {
  if (!id) return null;
  const raw = states?.[id]?.state;
  if (raw === null || raw === undefined) return null;
  const s = String(raw).trim().toLowerCase();
  if (s === '' || s === 'unknown' || s === 'unavailable' || s === 'nan') return null;
  return raw;
}

function getNum(id, fallback = 0) {
  const raw = getState(id);
  if (raw === null) return fallback;
  const n = Number(raw);
  return Number.isFinite(n) ? n : fallback;
}

function getBoolOn(id) {
  const raw = getState(id);
  if (raw === null) return false;
  return String(raw).trim().toLowerCase() === 'on';
}

// ---------- ENABLE FLAG ----------
const predictiveEnabled = getBoolOn('input_boolean.komfovent_predictive');

// ---------- REALTIME DATA ----------
const co2 =
  Number(global.get('komfovent.telemetry_last_co2')) ||
  getNum(ents.co2 || 'sensor.oro_stotele_carbon_dioxide', 0);

const telemetryRate = Number(global.get('komfovent.telemetry_rate'));
const threshold = Number(global.get('komfovent.auto_co2_on_threshold') || 750);

const alarm = String(getState(ents.alarm || 'alarm_control_panel.home') || 'armed_away');
const occupied = (alarm === 'disarmed');

// ---------- HOOD DETECTION ----------
const hoodEntity = ents.hood_power || 'sensor.hood_socket_power';
const hoodPower = getNum(hoodEntity, 0);
const hoodActive = Number.isFinite(hoodPower) && hoodPower >= 75;
const cookingNow = hoodActive;

// ---------- LOCAL CO2 HISTORY (Patobulinimas 1) ----------
const now = Date.now();

let pts = flow.get('predictive_co2_points') || [];
if (!Array.isArray(pts)) pts = [];

if (Number.isFinite(co2) && co2 > 0) {
  pts.push({ ts: now, co2: Number(co2) });
}

// laikom 4 val. istoriją
pts = pts.filter(p => (now - Number(p.ts || 0)) <= 240 * 60000);
flow.set('predictive_co2_points', pts);

// skaičiuojam local rate per paskutines ~30 min
let localRate30 = null;
const recent = pts.filter(p => (now - p.ts) <= 35 * 60000);

if (recent.length >= 2) {
  const first = recent[0];
  const last = recent[recent.length - 1];
  const dtMin = (last.ts - first.ts) / 60000;
  if (dtMin >= 10) {
    localRate30 = (last.co2 - first.co2) / dtMin;
  }
}

// galutinis rate
let effectiveRate = null;
let rateSource = 'none';

if (Number.isFinite(telemetryRate)) {
  effectiveRate = telemetryRate;
  rateSource = 'telemetry';
} else if (Number.isFinite(localRate30)) {
  effectiveRate = localRate30;
  rateSource = 'local_30m';
} else {
  effectiveRate = 0;
  rateSource = 'zero_fallback';
}

effectiveRate = Number(Number(effectiveRate).toFixed(2));

// ---------- TIME CONTEXT (Patobulinimas 2: 30 min bucket) ----------
const nowDate = new Date();
const bucket = Math.floor((nowDate.getHours() * 60 + nowDate.getMinutes()) / 30);
const dowNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const dow = dowNames[nowDate.getDay()];

const matrixKey = `${dow}_${bucket}_${occupied}`;
const hist = matrix?.data?.[matrixKey] || null;

// ---------- FORECAST ----------
let f30;
let f60;
let forecastSource30 = 'rate';
let forecastSource60 = 'rate';

if (hist && Number.isFinite(Number(hist.mean_growth_30))) {
  f30 = Math.round(co2 + Number(hist.mean_growth_30));
  forecastSource30 = 'matrix_growth_30';
} else {
  f30 = Math.round(co2 + effectiveRate * 30);
}

if (hist && Number.isFinite(Number(hist.mean_growth_60))) {
  f60 = Math.round(co2 + Number(hist.mean_growth_60));
  forecastSource60 = 'matrix_growth_60';
} else {
  f60 = Math.round(co2 + effectiveRate * 60);
}

// ---------- RISK MODEL ----------
let baseRisk = 0;
let anomalyStatus = 'normal';

if (!predictiveEnabled) {
  baseRisk = 0;
  anomalyStatus = 'disabled';
} else {
  if (f30 >= threshold) baseRisk = 6;
  else if (f60 >= (threshold - 50)) baseRisk = 3;
  else if (effectiveRate > 0.5) baseRisk = 1;

  if (cookingNow) {
    baseRisk = 0;
    anomalyStatus = 'cooking_active';
  }
}

const riskScore = clamp(0, 10, baseRisk);

// ---------- LOG RECORD ----------
const rec = {
  schema_ver,
  flow_ver,

  module: 'predictive',
  kind: 'shadow_tick',

  ts: new Date().toISOString(),

  predictive_enabled: predictiveEnabled,

  occupied,
  alarm_state: alarm,

  dow,
  hour: nowDate.getHours(),
  bucket_minutes: 30,

  co2,
  rate: effectiveRate,
  telemetry_rate: Number.isFinite(telemetryRate) ? Number(Number(telemetryRate).toFixed(2)) : null,
  local_rate_30m: Number.isFinite(localRate30) ? Number(Number(localRate30).toFixed(2)) : null,
  rate_source: rateSource,

  hood_active: hoodActive,
  hood_power_w: Number.isFinite(hoodPower) ? Math.round(hoodPower) : null,
  hood_entity: hoodEntity,

  cooking_mode: cookingNow,

  co2_f_30: f30,
  co2_f_60: f60,
  forecast_source_30: forecastSource30,
  forecast_source_60: forecastSource60,

  matrix_key: matrixKey,
  matrix_confidence_level: matrix?.confidence_info?.level || 'low',
  matrix_training_days: matrix?.training_days_actual || 0,

  history_mean_co2: hist ? hist.mean_co2 : null,
  history_mean_rate: hist ? hist.mean_rate : null,
  history_mean_growth_30: hist ? hist.mean_growth_30 : null,
  history_mean_growth_60: hist ? hist.mean_growth_60 : null,

  anomaly_status: anomalyStatus,
  risk_score: riskScore,

  pred_request: {
    action_level: !predictiveEnabled ? 0 : (riskScore >= 8 ? 3 : (riskScore >= 6 ? 2 : (riskScore >= 4 ? 1 : 0))),
    fan_offset_pct: !predictiveEnabled ? 0 : (riskScore >= 8 ? 25 : (riskScore >= 6 ? 15 : (riskScore >= 4 ? 8 : 0))),
    note: !predictiveEnabled
      ? 'predictive_disabled'
      : (matrix?.confidence_info?.level || 'low')
  }
};

// saugom abiejose vietose
flow.set('predictive_last', rec);
global.set('predictive_last', rec);

msg.log_type = 'predictive';
msg.log_record = rec;

// ---------- AI ALERT ----------
let msgAi = null;

if (predictiveEnabled && riskScore >= 6 && occupied && !cookingNow) {
  msgAi = {
    chatId: Number(env.get("MY_TELEGRAM_ID")),
    ai_reply: true,
    topic: 'predictive_alert',
    payload:
      `⚠️ *Aukšta CO₂ rizika: ${riskScore}/10*\n` +
      `Prognozė: ${co2} → ${f30} ppm (+30min)\n` +
      `Šaltinis: ${forecastSource30}`
  };
}

// ---------- NODE STATUS ----------
node.status({
  fill: !predictiveEnabled
    ? 'grey'
    : (cookingNow ? 'yellow' : (riskScore >= 6 ? 'red' : 'green')),
  shape: 'dot',
  text: !predictiveEnabled
    ? `DISABLED | ${matrix?.confidence_info?.level || 'no-matrix'}`
    : (cookingNow
      ? `COOKING | R:${riskScore} | ${matrix?.confidence_info?.level || 'low'}`
      : `R:${riskScore} | ${co2}→${f30} | ${forecastSource30}`)
});

return [msg, msgAi];

const last = flow.get('predictive_last') || {};
const matrix = global.get('prediction_matrix') || {};
const text = String(msg.user_text || '').toLowerCase();

function fmtMatrix(m) {

  if (!m.data)
    return "📊 Predictive modelis dar nesugeneruotas.\nLaukite naktinio mokymosi (03:05).";

  const ci = m.confidence_info || {};

  return `📊 *Predictive modelio būsena (v${m.model_ver})*
━━━━━━━━━━━━━━━━━━━━
📅 *Mokymosi laikas:* ${m.training_days_actual} d. (max 45)
📈 *Tikslumas:* ${ci.level?.toUpperCase()} (${ci.is_live_ready ? '✅ LIVE READY' : '⚠️ SHADOW ONLY'})
🕒 *Sugeneruota:* ${new Date(m.generated_at).toLocaleString('lt-LT')}
💡 _Sprendimai remiasi ${Object.keys(m.data).length} elgsenos bucket'ų._`;

}

function fmtShadow(u) {

  if (!u.ts)
    return '🧠 Predictive dar neturi duomenų.';

  return `🧠 *Predictive analizė*

• Rizika: *${u.risk_score}/10*
• CO₂ dabar: *${u.co2} ppm*
• Prognozė 30 min: *${u.co2_f_30} ppm*

📊 *Prognozės šaltinis:* ${u.forecast_source_30}

📜 *Statusas:* ${String(u.anomaly_status || 'normal').toUpperCase()}`;

}

let reply;

if (text.includes('matrix'))
  reply = fmtMatrix(matrix);

else if (
  text.includes('shadow') ||
  text.includes('risk') ||
  text.includes('rizika') ||
  text.includes('predictive')
)
  reply = fmtShadow(last);

else
  reply =
    `🧠 *Predictive informacija*

Galimos komandos:

/predictive – išsami prognozė
/status – sistemos būsena`;

msg.ai_reply = true;

msg.payload = {
  chatId: msg.chatId,
  text: reply,
  parse_mode: 'Markdown'
};

return msg;

// Išsaugom paskutinį predictive įrašą AI užklausoms
if (msg && msg.log_record && typeof msg.log_record === 'object') {
  flow.set('predictive_last', msg.log_record);
}
return msg;

const baseDir = '/data/logs/komfovent';
const maxDays = msg.training_window_max_days || 45;

// Naudojame find - tai saugiausias būdas, kurį supranta tavo sistema
msg.payload = `find ${baseDir} -name "komfovent_telemetry_*.jsonl" -mtime -${maxDays} -exec cat {} +`;

node.status({ fill: "blue", shape: "ring", text: `Training window: ${maxDays}d` });
return msg;

// Process Matrix Stats (30m buckets)
// Patobulinimai:
// - bucket_minutes = 30
// - išlaikom mean_rate
// - papildomai skaičiuojam mean_growth_30 ir mean_growth_60

function welfordInit() {
  return { n: 0, mean: 0, M2: 0 };
}

function welfordAdd(st, x) {
  st.n += 1;
  const delta = x - st.mean;
  st.mean += delta / st.n;
  const delta2 = x - st.mean;
  st.M2 += delta * delta2;
}

function welfordStd(st) {
  if (st.n < 2) return 0;
  return Math.sqrt(st.M2 / (st.n - 1));
}

const schema_ver = global.get('schema_ver');
const model_ver = global.get('model_ver');

let lines = String(msg.payload || '').split('\n').filter(Boolean);
let matrix = {};
let uniqueDays = new Set();
let timeline = [];

// ---------- 1) Surenkam telemetry į timeline ----------
for (const line of lines) {
  let d;
  try {
    d = JSON.parse(line);
  } catch (e) {
    continue;
  }

  if (!d.ts || d.co2 == null) continue;

  const tsMs = new Date(d.ts).getTime();
  const co2 = Number(d.co2);

  if (!Number.isFinite(tsMs) || !Number.isFinite(co2)) continue;

  timeline.push({
    ts: tsMs,
    co2,
    dow: d.dow,
    occupied: Boolean(d.occupied)
  });

  const dayStr = String(d.ts).split('T')[0];
  if (dayStr) uniqueDays.add(dayStr);
}

timeline.sort((a, b) => a.ts - b.ts);

// ---------- 2) Skaičiuojam statistiką per 30 min bucket ----------
for (let i = 0; i < timeline.length; i++) {
  const p = timeline[i];
  const dtObj = new Date(p.ts);

  const bucket = Math.floor((dtObj.getHours() * 60 + dtObj.getMinutes()) / 30);
  const key = `${p.dow}_${bucket}_${p.occupied}`;

  if (!matrix[key]) {
    matrix[key] = {
      co2: welfordInit(),
      rate: welfordInit(),
      growth30: welfordInit(),
      growth60: welfordInit(),
      n: 0
    };
  }

  matrix[key].n += 1;
  welfordAdd(matrix[key].co2, p.co2);

  // --- rate iš sekos ---
  if (i > 0) {
    const prev = timeline[i - 1];
    const dtMin = (p.ts - prev.ts) / 60000;

    if (dtMin > 0 && dtMin <= 20) {
      const rate = (p.co2 - prev.co2) / dtMin;
      if (Number.isFinite(rate)) {
        welfordAdd(matrix[key].rate, rate);
      }
    }
  }

  // --- growth 30 min ---
  for (let j = i + 1; j < timeline.length; j++) {
    const dtMin = (timeline[j].ts - p.ts) / 60000;

    if (dtMin >= 25 && dtMin <= 40) {
      const growth = timeline[j].co2 - p.co2;
      if (Number.isFinite(growth)) {
        welfordAdd(matrix[key].growth30, growth);
      }
      break;
    }

    if (dtMin > 45) break;
  }

  // --- growth 60 min ---
  for (let j = i + 1; j < timeline.length; j++) {
    const dtMin = (timeline[j].ts - p.ts) / 60000;

    if (dtMin >= 55 && dtMin <= 70) {
      const growth = timeline[j].co2 - p.co2;
      if (Number.isFinite(growth)) {
        welfordAdd(matrix[key].growth60, growth);
      }
      break;
    }

    if (dtMin > 75) break;
  }
}

// ---------- 3) Confidence ----------
const trainingDays = uniqueDays.size;

let conf = 'low';
if (trainingDays >= 30) conf = 'very_high';
else if (trainingDays >= 16) conf = 'high';
else if (trainingDays >= 8) conf = 'medium';

// ---------- 4) Final matrix ----------
let data = {};

for (const k of Object.keys(matrix)) {
  const m = matrix[k];

  data[k] = {
    mean_co2: Number(m.co2.mean.toFixed(2)),
    std_co2: Number(welfordStd(m.co2).toFixed(2)),
    mean_rate: Number(m.rate.mean.toFixed(2)),
    std_rate: Number(welfordStd(m.rate).toFixed(2)),
    mean_growth_30: Number(m.growth30.mean.toFixed(2)),
    std_growth_30: Number(welfordStd(m.growth30).toFixed(2)),
    mean_growth_60: Number(m.growth60.mean.toFixed(2)),
    std_growth_60: Number(welfordStd(m.growth60).toFixed(2)),
    n: m.n
  };
}

const finalMatrix = {
  schema_ver,
  model_ver,
  bucket_minutes: 30,
  generated_at: new Date().toISOString(),
  training_days_actual: trainingDays,
  confidence_info: {
    level: conf,
    is_live_ready: (trainingDays >= 16)
  },
  data
};

global.set('prediction_matrix', finalMatrix);
msg.payload = JSON.stringify(finalMatrix);
msg.filename = '/data/state/komfovent/prediction_matrix.json';

node.status({
  fill: 'blue',
  shape: 'dot',
  text: `Model 30m | Days: ${trainingDays} | Buckets: ${Object.keys(data).length}`
});

return msg;
